sys_script_client.script:
function onChange(control, oldValue, newValue, isLoading) {
    if (isLoading) return;

    g_form.clearOptions('servicenow_sub_category');
    g_form.setValue('servicenow_sub_category', '');

    if (!newValue) return;

    g_form.addOption('servicenow_sub_category', '', '-- Select Sub-Category --');

    var categoryLabel = g_form.getDisplayValue('servicenow_category'); // <-- IMPORTANT

    var ga = new GlideAjax('PulseCategoryAjax');
    ga.addParam('sysparm_name', 'getSubCategories');
    ga.addParam('sysparm_table', g_form.getValue('ticket_type'));
    ga.addParam('sysparm_category', categoryLabel); // <-- label (e.g. "Database")
    ga.getXMLAnswer(function (answer) {
        if (!answer) return;

        var subs = JSON.parse(answer);
        for (var i = 0; i < subs.length; i++) {
            g_form.addOption('servicenow_sub_category', subs[i].value, subs[i].label);
        }
    });
}
